#!/usr/bin/env node
/* =====================================================================
 * Seed ALL BFI YouTube videos into testimonial_videos + education_videos
 * production tables. Clears existing rows then inserts fresh data.
 *
 * Source: scripts/bfi_testimonials.json + scripts/bfi_education.json
 *         (generated by scripts/categorize-videos.mjs from yt-dlp)
 *
 * Run:  node scripts/patch-seed-all-videos.mjs
 * ===================================================================== */
import pg from "pg";
import { readFileSync } from "fs";
import { fileURLToPath } from "url";
import { dirname, join } from "path";

const { Client } = pg;
const __dirname = dirname(fileURLToPath(import.meta.url));

const DB_URI =
  process.env.DATABASE_URI ??
  "postgresql://postgres.acugkaaiyzbckwafudxa:deepakDigitalAura@aws-1-ap-northeast-2.pooler.supabase.com:5432/postgres";

const rand24 = () =>
  Array.from({ length: 24 }, () =>
    Math.floor(Math.random() * 16).toString(16)
  ).join("");

// --- Load categorized data ---
const testimonials = JSON.parse(
  readFileSync(join(__dirname, "bfi_testimonials.json"), "utf8")
);
const education = JSON.parse(
  readFileSync(join(__dirname, "bfi_education.json"), "utf8")
);

console.log(`Loaded: ${testimonials.length} testimonials, ${education.length} education videos`);

// --- Extract patient name + quote from title ---
function parseTestimonial(v) {
  const t = v.title;
  // Try to pull a name from common patterns
  let name = t;
  let quote = "A heartfelt journey shared with Bavishi Fertility Institute.";

  // "25 Years of Waiting, One Miracle | IVF Success Story"
  const pipeIdx = t.indexOf("|");
  if (pipeIdx > 0) name = t.slice(0, pipeIdx).trim();

  // Common patterns for quote generation
  if (/\d+\s*years?\s*of\s*wait/i.test(t)) {
    const m = t.match(/(\d+)\s*years?\s*of\s*wait/i);
    if (m) quote = `After ${m[1]} long years of waiting, Bavishi Fertility Institute helped us achieve our dream.`;
  } else if (/\d+\s*years?\s*of\s*hope/i.test(t)) {
    const m = t.match(/(\d+)\s*years?\s*of\s*hope/i);
    if (m) quote = `${m[1]} years of hope — and Bavishi Fertility Institute made it happen.`;
  } else if (/failed\s*treatment/i.test(t)) {
    quote = "After failed treatments elsewhere, Bavishi Fertility Institute gave us our miracle.";
  } else if (/1st\s*ivf\s*cycle|first\s*ivf\s*cycle/i.test(t)) {
    quote = "We succeeded in our very first IVF cycle at Bavishi Fertility Institute.";
  } else if (/twin/i.test(t)) {
    quote = "We were blessed with twins thanks to the expert care at Bavishi Fertility Institute.";
  } else if (/natural\s*miracle|natural\s*pregnancy/i.test(t)) {
    quote = "After our IVF miracle, we were blessed with a natural pregnancy — thanks to BFI.";
  } else if (/dream.*came\s*true/i.test(t)) {
    quote = "Our dream of becoming parents finally came true at Bavishi Fertility Institute.";
  } else if (/\d+\s*ivf.*cycle/i.test(t)) {
    const m = t.match(/(\d+)\s*ivf/i);
    if (m) quote = `After ${m[1]} IVF cycles, Bavishi Fertility Institute finally blessed us.`;
  } else if (/personalised\s*care|personalized\s*care/i.test(t)) {
    quote = "The personalised care at Bavishi Fertility Institute made all the difference.";
  } else if (/hope.*care|journey.*hope/i.test(t)) {
    quote = "A journey full of hope — guided with care by the Bavishi Fertility Institute team.";
  } else if (/canada/i.test(t)) {
    quote = "Being treated from Canada was seamless — the BFI team's communication was exceptional.";
  } else if (/parenthood/i.test(t)) {
    quote = "Our journey to parenthood was made possible by the dedicated team at BFI.";
  } else if (/ivf\s*success|success.*ivf/i.test(t)) {
    quote = "Our IVF journey at Bavishi Fertility Institute was a complete success.";
  } else if (/review/i.test(t)) {
    quote = "We are grateful for the expert treatment and compassionate care at BFI.";
  } else if (/bavishi\s*testimonials?\s*\d/i.test(t)) {
    quote = "Words cannot express how grateful we are to the BFI team for changing our lives.";
  }

  // Clean up the name — remove trailing descriptors
  name = name
    .replace(/\s*testimonial\s*$/i, "")
    .replace(/\s*\|.*$/, "")
    .replace(/^(from|feedback\s*from)\s+/i, "")
    .replace(/\s*review.*$/i, "")
    .replace(/\s*at\s*bavishi.*$/i, "")
    .replace(/bavishi\s*fertility\s*institute.*$/i, "")
    .replace(/^fertility\s*treatment\s*testimonial\s*(by\s*)?/i, "")
    .replace(/^testimonial\s*(for\s*bavishi\s*fertility\s*institute\s*)?(by\s*patient\s*)?/i, "")
    .replace(/^ahmedabad\s*fertility\s*treatment\s*testimonial\s*from\s*/i, "")
    .trim();

  if (!name || name.length < 2) name = "BFI Patient";

  return { name, quote };
}

const client = new Client({
  connectionString: DB_URI,
  ssl: { rejectUnauthorized: false },
});
await client.connect();
console.log("Connected to production DB.");

// ---- Seed TESTIMONIAL VIDEOS ----
await client.query("DELETE FROM testimonial_videos");
console.log("[testimonials] Cleared existing rows.");

let tOrder = 0;
for (const v of testimonials) {
  const { name, quote } = parseTestimonial(v);
  await client.query(
    `INSERT INTO testimonial_videos
       (patient_name, rating, youtube_id, quote, published, "order", updated_at, created_at)
     VALUES ($1, $2, $3, $4, $5, $6, NOW(), NOW())`,
    [name, 5, v.id, quote, true, tOrder++]
  );
}
console.log(`[testimonials] Inserted ${tOrder} rows.`);

// ---- Seed EDUCATION VIDEOS ----
await client.query("DELETE FROM education_videos");
console.log("[education] Cleared existing rows.");

let eOrder = 0;
for (const v of education) {
  // Build a clean title — strip non-ASCII cruft for display
  const cleanTitle = v.title
    .replace(/[^\x00-\x7Fऀ-ॿ઀-૿]+/g, " ")
    .replace(/\s{2,}/g, " ")
    .trim();

  await client.query(
    `INSERT INTO education_videos
       (title, category, youtube_id, description, published, "order", updated_at, created_at)
     VALUES ($1, $2, $3, $4, $5, $6, NOW(), NOW())`,
    [
      cleanTitle || v.title,
      v.category,
      v.id,
      null,
      true,
      eOrder++,
    ]
  );
}
console.log(`[education] Inserted ${eOrder} rows.`);

await client.end();
console.log("\nDone. Production DB seeded successfully.");
